import { GoogleGenAI, Schema, Type } from "@google/genai";

const API_KEY = "AIzaSyDUo8NlOC56gWYEETviAceCUd-mxoruplQ";
const ai = new GoogleGenAI({ apiKey: API_KEY });

const MODELS = ["gemini-2.5-flash", "gemini-2.5-flash-latest"];

const eduInterpretationSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    attainmentAnalysis: { type: Type.STRING, description: "Analysis of the distribution of educational attainment (Bachelors vs Masters vs Doctoral)." },
    licenseImpact: { type: Type.STRING, description: "Insight on how having a professional license affects employment rate and salary." },
    feederSchools: { type: Type.STRING, description: "Commentary on the top source schools for primary and secondary education." },
    salaryProgression: { type: Type.STRING, description: "Analysis of the Return on Education: How salary increases with higher degrees." },
  },
  required: ["attainmentAnalysis", "licenseImpact", "feederSchools", "salaryProgression"]
};

export interface EduInterpretations {
    attainmentAnalysis: string;
    licenseImpact: string;
    feederSchools: string;
    salaryProgression: string;
}

export const generateEducationInsights = async (stats: any): Promise<EduInterpretations> => {
  const prompt = `
    You are a Data Analyst for a University. Analyze the following Education Statistics and provide professional insights.

    **Data Context:**
    1. **Attainment**: ${JSON.stringify(stats.attainmentCounts)}
    2. **License Impact**: 
       - Licensed Alumni: Avg Salary ${stats.licenseStats.licensedSalary}, Emp Rate ${stats.licenseStats.licensedEmpRate}%
       - Non-Licensed: Avg Salary ${stats.licenseStats.nonLicensedSalary}, Emp Rate ${stats.licenseStats.nonLicensedEmpRate}%
    3. **Top Feeder Schools**: ${JSON.stringify(stats.feederSchools)}
    4. **Salary by Degree**: ${JSON.stringify(stats.degreeSalaries)}

    **Instructions:**
    - **License Impact**: Explicitly state the percentage difference if significant (e.g., "Licensed alumni earn X% more...").
    - **Salary Progression**: Evaluate if pursuing a Master's or Doctorate yields a financial return based on the data.
    - Keep interpretations concise (2-3 sentences).

    Output strictly JSON.
  `;

  for (const model of MODELS) {
    try {
      const response = await ai.models.generateContent({
        model: model,
        contents: { parts: [{ text: prompt }] },
        config: {
          responseMimeType: "application/json",
          responseSchema: eduInterpretationSchema,
        },
      });

      if (response.text) {
          return JSON.parse(response.text) as EduInterpretations;
      }
    } catch (error) {
       console.warn(`Model ${model} failed for edu analytics:`, error);
    }
  }

  return {
      attainmentAnalysis: "Data unavailable.",
      licenseImpact: "Data unavailable.",
      feederSchools: "Data unavailable.",
      salaryProgression: "Data unavailable."
  };
};

import React, { useEffect, useState } from 'react';
import { BookOpen, Award, School, TrendingUp, DollarSign, Lightbulb, Loader2, GraduationCap, CheckCircle2, XCircle } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line, Legend, Cell, PieChart, Pie } from 'recharts';
import { generateEducationInsights, EduInterpretations } from '../services/educationAI';

// Helper to estimate salary from range string
const estimateSalary = (range: string): number => {
    if (!range) return 0;
    if (range.includes('Below 10,000')) return 8000;
    if (range.includes('Below 15,000')) return 12000;
    if (range.includes('15,000')) return 17500;
    if (range.includes('20,001')) return 25000;
    if (range.includes('30,001')) return 40000;
    if (range.includes('50,001') && range.includes('100,000')) return 75000;
    if (range.includes('100,001')) return 250000; // Mid of 100k-500k
    if (range.includes('Above 50,000')) return 60000;
    return 0;
};

// Interpretation Component
const InsightCard = ({ text, loading }: { text?: string, loading: boolean }) => (
    <div className="mt-4 p-4 bg-gradient-to-br from-blue-50 to-indigo-50 rounded-xl border border-blue-100 flex gap-3 relative overflow-hidden">
        <Lightbulb className="text-blue-600 shrink-0 mt-1" size={18} />
        <div className="relative z-10 w-full">
            <h5 className="text-[10px] font-bold text-blue-800 uppercase tracking-widest mb-1">AI Analysis</h5>
            {loading ? (
                <div className="space-y-2 animate-pulse">
                    <div className="h-2 bg-blue-200 rounded w-full"></div>
                    <div className="h-2 bg-blue-200 rounded w-3/4"></div>
                </div>
            ) : (
                <p className="text-xs text-slate-700 font-medium leading-relaxed">{text || "Insufficient data for analysis."}</p>
            )}
        </div>
    </div>
);

const EducationAnalytics: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [loadingAI, setLoadingAI] = useState(false);
  const [interpretations, setInterpretations] = useState<EduInterpretations | null>(null);

  // State for Charts
  const [attainmentData, setAttainmentData] = useState<any[]>([]);
  const [feederSchools, setFeederSchools] = useState<{ primary: any[], secondary: any[] }>({ primary: [], secondary: [] });
  const [licenseStats, setLicenseStats] = useState<any>(null);
  const [gradTrends, setGradTrends] = useState<any[]>([]);
  const [salaryByDegree, setSalaryByDegree] = useState<any[]>([]);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
        // 1. Fetch Education Data
        const { data: eduData, error: eduError } = await supabase.from('education_information').select('*');
        if (eduError) throw eduError;

        // 2. Fetch Employment Data (for cross-referencing)
        const { data: empData, error: empError } = await supabase.from('employment_information').select('*');
        if (empError) throw empError;

        // Map employment by survey_id for quick lookup
        const empMap = new Map();
        empData?.forEach(e => empMap.set(e.survey_response_id, e));

        // --- PROCESSING ---

        // A. Attainment & Graduation Trends
        const degrees = { Bachelors: 0, Masters: 0, Doctoral: 0 };
        const years: Record<string, number> = {};

        // B. Feeder Schools
        const primaryCount: Record<string, number> = {};
        const secondaryCount: Record<string, number> = {};

        // C. License Impact Stats
        let licEmp = 0, licTotal = 0, licSalSum = 0, licSalCount = 0;
        let nonLicEmp = 0, nonLicTotal = 0, nonLicSalSum = 0, nonLicSalCount = 0;

        // D. Salary by Degree Stats
        const degreeSalaries: Record<string, { sum: number, count: number }> = {
            "Bachelor's": { sum: 0, count: 0 },
            "Master's": { sum: 0, count: 0 },
            "Doctoral": { sum: 0, count: 0 }
        };

        eduData.forEach(edu => {
            // Highest Degree Logic
            let level = "Bachelor's";
            if (edu.doctoral_degree) {
                level = "Doctoral";
                degrees.Doctoral++;
            } else if (edu.masters_degree) {
                level = "Master's";
                degrees.Masters++;
            } else {
                degrees.Bachelors++;
            }

            // Feeder Schools
            if (edu.primary_school) primaryCount[edu.primary_school] = (primaryCount[edu.primary_school] || 0) + 1;
            if (edu.secondary_school) secondaryCount[edu.secondary_school] = (secondaryCount[edu.secondary_school] || 0) + 1;

            // Graduation Trend (Bachelor's year used as baseline)
            if (edu.bachelors_year_graduated) {
                const y = edu.bachelors_year_graduated;
                years[y] = (years[y] || 0) + 1;
            }

            // Cross-Reference with Employment
            const empRecord = empMap.get(edu.survey_response_id);
            if (empRecord) {
                const isEmployed = empRecord.employment_status === 'Employed' || empRecord.employment_status === 'Self-employed';
                const salary = estimateSalary(empRecord.salary_range || empRecord.business_revenue);

                // License Impact
                if (edu.professional_license) {
                    licTotal++;
                    if (isEmployed) licEmp++;
                    if (salary > 0) { licSalSum += salary; licSalCount++; }
                } else {
                    nonLicTotal++;
                    if (isEmployed) nonLicEmp++;
                    if (salary > 0) { nonLicSalSum += salary; nonLicSalCount++; }
                }

                // Salary by Degree
                if (salary > 0) {
                    degreeSalaries[level].sum += salary;
                    degreeSalaries[level].count++;
                }
            }
        });

        // --- FORMATTING FOR CHARTS ---

        // Attainment
        setAttainmentData([
            { name: "Bachelor's", value: degrees.Bachelors, fill: '#60a5fa' },
            { name: "Master's", value: degrees.Masters, fill: '#818cf8' },
            { name: "Doctoral", value: degrees.Doctoral, fill: '#c084fc' },
        ]);

        // Feeder Schools (Top 5)
        const topPrimary = Object.entries(primaryCount).sort((a,b) => b[1] - a[1]).slice(0, 5).map(([name, count]) => ({ name, count }));
        const topSecondary = Object.entries(secondaryCount).sort((a,b) => b[1] - a[1]).slice(0, 5).map(([name, count]) => ({ name, count }));
        setFeederSchools({ primary: topPrimary, secondary: topSecondary });

        // License Stats
        setLicenseStats({
            licensedEmpRate: licTotal > 0 ? Math.round((licEmp / licTotal) * 100) : 0,
            licensedSalary: licSalCount > 0 ? Math.round(licSalSum / licSalCount) : 0,
            nonLicensedEmpRate: nonLicTotal > 0 ? Math.round((nonLicEmp / nonLicTotal) * 100) : 0,
            nonLicensedSalary: nonLicSalCount > 0 ? Math.round(nonLicSalSum / nonLicSalCount) : 0,
            licensedCount: licTotal,
            nonLicensedCount: nonLicTotal
        });

        // Grad Trends
        const trendData = Object.entries(years).map(([year, count]) => ({ year, count })).sort((a,b) => parseInt(a.year) - parseInt(b.year));
        setGradTrends(trendData);

        // Salary by Degree
        const salData = Object.entries(degreeSalaries).map(([level, data]) => ({
            name: level,
            avgSalary: data.count > 0 ? Math.round(data.sum / data.count) : 0
        }));
        setSalaryByDegree(salData);

        // --- AI GENERATION ---
        setLoading(false);
        setLoadingAI(true);
        const statsForAI = {
            attainmentCounts: degrees,
            licenseStats: {
                licensedEmpRate: licTotal > 0 ? Math.round((licEmp / licTotal) * 100) : 0,
                licensedSalary: licSalCount > 0 ? Math.round(licSalSum / licSalCount) : 0,
                nonLicensedEmpRate: nonLicTotal > 0 ? Math.round((nonLicEmp / nonLicTotal) * 100) : 0,
                nonLicensedSalary: nonLicSalCount > 0 ? Math.round(nonLicSalSum / nonLicSalCount) : 0,
            },
            feederSchools: { primary: topPrimary.slice(0,3), secondary: topSecondary.slice(0,3) },
            degreeSalaries: salData
        };
        const insights = await generateEducationInsights(statsForAI);
        setInterpretations(insights);
        setLoadingAI(false);

    } catch (e) {
        console.error("Fetch Error:", e);
        setLoading(false);
        setLoadingAI(false);
    }
  };

  return (
    <div className="space-y-8 animate-fade-in pb-10">

        {/* ROW 1: Attainment & Schools */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Highest Educational Attainment */}
            <div className="bg-white/40 backdrop-blur-xl border border-white/50 shadow-lg shadow-indigo-500/5 p-6 rounded-3xl lg:col-span-1 flex flex-col">
                <div className="flex items-center gap-3 mb-6">
                    <div className="p-2 bg-blue-100 text-blue-600 rounded-xl"><GraduationCap size={20}/></div>
                    <h4 className="font-bold text-slate-800">Educational Attainment</h4>
                </div>
                <div className="h-48 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={attainmentData} layout="vertical" margin={{ top: 0, right: 30, left: 0, bottom: 0 }}>
                            <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} opacity={0.3} />
                            <XAxis type="number" hide />
                            <YAxis dataKey="name" type="category" width={80} tick={{fontSize: 11, fontWeight: 'bold', fill: '#64748b'}} />
                            <Tooltip cursor={{fill: '#f1f5f9'}} contentStyle={{borderRadius: '12px', border: 'none'}} />
                            <Bar dataKey="value" radius={[0, 4, 4, 0]} barSize={24}>
                                {attainmentData.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={entry.fill} />
                                ))}
                            </Bar>
                        </BarChart>
                    </ResponsiveContainer>
                </div>
                <InsightCard text={interpretations?.attainmentAnalysis} loading={loadingAI} />
            </div>

            {/* School Source Analysis */}
            <div className="bg-white/40 backdrop-blur-xl border border-white/50 shadow-lg shadow-indigo-500/5 p-6 rounded-3xl lg:col-span-2 flex flex-col">
                <div className="flex items-center gap-3 mb-6">
                    <div className="p-2 bg-indigo-100 text-indigo-600 rounded-xl"><School size={20}/></div>
                    <h4 className="font-bold text-slate-800">Top Feeder Schools</h4>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 flex-grow">
                    {/* Primary */}
                    <div className="bg-white/60 rounded-xl border border-white/60 p-4">
                        <h5 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 flex items-center gap-2">
                            <span className="w-2 h-2 rounded-full bg-indigo-400"></span> Primary Level
                        </h5>
                        <ul className="space-y-3">
                            {feederSchools.primary.map((school, i) => (
                                <li key={i} className="flex justify-between items-center text-sm">
                                    <span className="text-slate-700 font-medium truncate pr-2" title={school.name}>{school.name}</span>
                                    <span className="font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded text-xs">{school.count}</span>
                                </li>
                            ))}
                            {feederSchools.primary.length === 0 && <li className="text-slate-400 text-xs italic">No data available</li>}
                        </ul>
                    </div>
                    {/* Secondary */}
                    <div className="bg-white/60 rounded-xl border border-white/60 p-4">
                        <h5 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 flex items-center gap-2">
                            <span className="w-2 h-2 rounded-full bg-blue-400"></span> Secondary Level
                        </h5>
                        <ul className="space-y-3">
                            {feederSchools.secondary.map((school, i) => (
                                <li key={i} className="flex justify-between items-center text-sm">
                                    <span className="text-slate-700 font-medium truncate pr-2" title={school.name}>{school.name}</span>
                                    <span className="font-bold text-blue-600 bg-blue-50 px-2 py-0.5 rounded text-xs">{school.count}</span>
                                </li>
                            ))}
                            {feederSchools.secondary.length === 0 && <li className="text-slate-400 text-xs italic">No data available</li>}
                        </ul>
                    </div>
                </div>
                <InsightCard text={interpretations?.feederSchools} loading={loadingAI} />
            </div>
        </div>

        {/* ROW 2: License Impact (The "Money" Slide) */}
        <div className="bg-gradient-to-r from-slate-800 to-slate-900 rounded-3xl p-8 text-white shadow-2xl relative overflow-hidden">
            {/* Decoration */}
            <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/20 rounded-full blur-[80px] translate-x-1/3 -translate-y-1/3"></div>

            <div className="relative z-10 grid grid-cols-1 lg:grid-cols-3 gap-8 items-center">
                <div className="col-span-1 space-y-4">
                    <div className="inline-flex items-center gap-2 px-3 py-1 bg-white/10 rounded-full border border-white/20 text-xs font-bold text-indigo-200">
                        <Award size={14} /> Professional License Impact
                    </div>
                    <h3 className="text-3xl font-black leading-tight">Does a License Boost Careers?</h3>
                    <p className="text-slate-300 text-sm leading-relaxed">
                        Comparing employment rates and average monthly income between licensed professionals and non-licensed graduates.
                    </p>

                    {/* Dynamic AI Text directly embedded */}
                    <div className="bg-white/10 backdrop-blur-md p-4 rounded-xl border border-white/10 mt-4">
                        {loadingAI ? <div className="h-4 bg-white/20 rounded animate-pulse w-3/4"></div> : (
                            <p className="text-xs font-medium text-indigo-100 italic">
                                " {interpretations?.licenseImpact || "Analysis pending..."} "
                            </p>
                        )}
                    </div>
                </div>

                <div className="col-span-2 grid grid-cols-1 sm:grid-cols-2 gap-4">
                    {/* Card: Licensed */}
                    <div className="bg-white text-slate-800 p-6 rounded-2xl shadow-lg transform hover:-translate-y-1 transition-transform">
                        <div className="flex justify-between items-start mb-4">
                            <h4 className="font-bold text-indigo-600 flex items-center gap-2">
                                <CheckCircle2 size={18}/> Licensed Alumni
                            </h4>
                            <span className="text-xs font-bold bg-indigo-100 text-indigo-700 px-2 py-1 rounded">n={licenseStats?.licensedCount || 0}</span>
                        </div>
                        <div className="space-y-4">
                            <div>
                                <p className="text-xs text-slate-400 font-bold uppercase">Employment Rate</p>
                                <p className="text-3xl font-black text-slate-800">{licenseStats?.licensedEmpRate || 0}%</p>
                            </div>
                            <div>
                                <p className="text-xs text-slate-400 font-bold uppercase">Avg. Monthly Income</p>
                                <p className="text-xl font-bold text-emerald-600">₱ {licenseStats?.licensedSalary?.toLocaleString() || 0}</p>
                            </div>
