                            <h4 className="font-bold text-slate-300 flex items-center gap-2">
                                <XCircle size={18}/> Non-Licensed
                            </h4>
                            <span className="text-xs font-bold bg-slate-600 text-slate-200 px-2 py-1 rounded">n={licenseStats?.nonLicensedCount || 0}</span>
                        </div>
                        <div className="space-y-4">
                            <div>
                                <p className="text-xs text-slate-400 font-bold uppercase">Employment Rate</p>
                                <p className="text-3xl font-black text-white">{licenseStats?.nonLicensedEmpRate || 0}%</p>
                            </div>
                            <div>
                                <p className="text-xs text-slate-400 font-bold uppercase">Avg. Monthly Income</p>
                                <p className="text-xl font-bold text-slate-200">₱ {licenseStats?.nonLicensedSalary?.toLocaleString() || 0}</p>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* ROW 3: Trends & Salary Progression */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            {/* Graduation Trends */}
            <div className="bg-white/40 backdrop-blur-xl border border-white/50 shadow-lg shadow-indigo-500/5 p-6 rounded-3xl">
                <div className="flex items-center gap-3 mb-6">
