// Helper to estimate salary from range string
const estimateSalary = (range: string): number => {
    if (!range) return 0;
    if (range.includes('Below 10,000')) return 8000;
    if (range.includes('Below 15,000')) return 12000;
    if (range.includes('15,000')) return 17500;
    if (range.includes('20,001')) return 25000;
    if (range.includes('30,001')) return 40000;
    if (range.includes('50,001') && range.includes('100,000')) return 75000;
    if (range.includes('100,001') && range.includes('500,000')) return 250000;
    if (range.includes('500,001') && range.includes('1,000,000')) return 750000;
    if (range.includes('Above 50,000')) return 60000;
    if (range.includes('Above 1,000,000')) return 1200000;
    return 0;
};

