                            <div>
                                <p className="text-xs text-slate-400 font-bold uppercase">Avg. Monthly Income</p>
                                <p className="text-xl font-bold text-slate-200">₱ {licenseStats?.nonLicensedSalary?.toLocaleString() || 0}</p>
                            </div>
