import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, AreaChart, Area, Legend } from 'recharts';
import { generateCommunityInsights, CommunityInterpretations } from '../services/communityAI';

// --- HELPERS ---

const categorizeOrg = (name: string): string => {
    const n = name.toLowerCase();
    if (n.includes('sk') || n.includes('sangguniang') || n.includes('barangay') || n.includes('lgu') || n.includes('municipality') || n.includes('city')) return 'LGU / Barangay';
    if (n.includes('church') || n.includes('ministry') || n.includes('parish') || n.includes('religious')) return 'Religious Group';
    if (n.includes('red cross') || n.includes('rotary') || n.includes('foundation') || n.includes('ngo') || n.includes('volunteer')) return 'NGO / Civic';
    if (n.includes('society') || n.includes('association') || n.includes('chapter') || n.includes('league')) return 'Professional Org';
    if (n.includes('alumni') || n.includes('student') || n.includes('university') || n.includes('college')) return 'School Org';
    return 'Other';
};

const categorizeRole = (role: string): 'Leader' | 'Officer' | 'Member' => {
    const r = role.toLowerCase();
    if (r.includes('president') || r.includes('chair') || r.includes('head') || r.includes('founder') || r.includes('director') || r.includes('captain')) return 'Leader';
    if (r.includes('secretary') || r.includes('treasurer') || r.includes('auditor') || r.includes('officer') || r.includes('manager') || r.includes('coordinator')) return 'Officer';
    return 'Member';
};

// Colors
const COLORS = ['#f43f5e', '#fb7185', '#fda4af', '#fecdd3', '#ffe4e6'];
const ROLE_COLORS = { Leader: '#be123c', Officer: '#e11d48', Member: '#fb7185' };

// Interpretation Component
const InsightCard = ({ text, loading }: { text?: string, loading: boolean }) => (
