    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
        // 1. Fetch All Tables
        const [commRes, empRes] = await Promise.all([
            supabase.from('community_engagement').select('*'),
            supabase.from('employment_information').select('*')
        ]);

        const commData = commRes.data || [];
        const empData = empRes.data || [];

        // Map Employment by Survey ID for Cross-Ref
        const empMap = new Map();
        // Sort to ensure latest is used
        [...empData].sort((a,b) => a.id - b.id).forEach(e => empMap.set(e.survey_response_id, e));

        // --- PROCESSING ---

        // A. Org Types & Top Orgs
        const typeCounts: Record<string, number> = {};
        const nameCounts: Record<string, number> = {};
        const roleCounts: Record<string, number> = { Leader: 0, Officer: 0, Member: 0 };
        const yearCounts: Record<string, number> = {};

        // B. Cross Section Containers
        let leadersTotal = 0, leadersManagers = 0;
        let membersTotal = 0, membersManagers = 0;

        // Track user engagement to avoid double counting same user in cross-section
        const userHighestRole = new Map<string, 'Leader' | 'Officer' | 'Member'>();

        commData.forEach(record => {
            if (!record.organization_name) return;

            // 1. Org Type
            const type = categorizeOrg(record.organization_name);
            typeCounts[type] = (typeCounts[type] || 0) + 1;

            // 2. Specific Name (Cleaned)
            const cleanName = record.organization_name.trim();
            nameCounts[cleanName] = (nameCounts[cleanName] || 0) + 1;

            // 3. Role
            const roleCat = categorizeRole(record.role || '');
            roleCounts[roleCat]++;

            // 4. Timeline
            // Fix: Handle text dates like "2023 - Present" by extracting first 4 digits
            if (record.date_affiliated) {
                let year = 'Unknown';
                // Regex to find 4 digits (e.g., 2023)
                const match = record.date_affiliated.toString().match(/\d{4}/);
                if (match) {
                    year = match[0];
                } else {
                    // Fallback to date parsing
                    const d = new Date(record.date_affiliated);
                    if (!isNaN(d.getFullYear())) year = d.getFullYear().toString();
                }

                if (year !== 'Unknown') {
                    yearCounts[year] = (yearCounts[year] || 0) + 1;
                }
            }

            // 5. User Role Tracking for Cross-Section
            // We promote them to highest role found (Leader > Officer > Member)
            const currentHighest = userHighestRole.get(record.survey_response_id);
            if (!currentHighest) {
                userHighestRole.set(record.survey_response_id, roleCat);
            } else if (roleCat === 'Leader') {
                userHighestRole.set(record.survey_response_id, 'Leader');
            } else if (roleCat === 'Officer' && currentHighest === 'Member') {
                userHighestRole.set(record.survey_response_id, 'Officer');
            }
        });

        // C. Cross-Section Calculation
        userHighestRole.forEach((role, surveyId) => {
            const emp = empMap.get(surveyId);
            if (emp) {
                const isManagerial = ['Managerial', 'Department Head', 'Director', 'Vice President', 'Executive', 'Supervisory'].includes(emp.current_job_level);

                if (role === 'Leader' || role === 'Officer') {
                    leadersTotal++;
                    if (isManagerial) leadersManagers++;
                } else {
                    membersTotal++;
                    if (isManagerial) membersManagers++;
                }
            }
        });

        // --- FORMATTING ---

        // Org Types
        const orgTypesFormatted = Object.entries(typeCounts)
            .map(([name, value]) => ({ name, value }))
            .sort((a,b) => b.value - a.value);
        setOrgTypeData(orgTypesFormatted);

        // Top Orgs
        const topOrgsFormatted = Object.entries(nameCounts)
            .map(([name, value]) => ({ name, value }))
            .sort((a,b) => b.value - a.value)
            .slice(0, 5);
        setTopOrgs(topOrgsFormatted);

        // Roles
        const roleDataFormatted = Object.entries(roleCounts).map(([name, value]) => ({ name, value }));
        setRoleData(roleDataFormatted);

        // Timeline
        const timelineFormatted = Object.entries(yearCounts)
            .map(([year, count]) => ({ year, count }))
            .sort((a,b) => parseInt(a.year) - parseInt(b.year))
            .slice(-5); // Last 5 years
        setTimelineData(timelineFormatted);

        // Cross Section Chart Data
        const leaderRate = leadersTotal > 0 ? Math.round((leadersManagers / leadersTotal) * 100) : 0;
        const memberRate = membersTotal > 0 ? Math.round((membersManagers / membersTotal) * 100) : 0;

        setCrossSectionData([
            { group: 'Community Leaders', percentage: leaderRate, fill: '#f59e0b' }, // Gold
            { group: 'Regular Members', percentage: memberRate, fill: '#94a3b8' }    // Slate
        ]);
        setCrossSectionStats({ leaderManagerialRate: leaderRate, memberManagerialRate: memberRate });

        // --- AI ---
