const CommunityAnalytics: React.FC<CommunityAnalyticsProps> = ({ autoAI = false }) => {
  const [loading, setLoading] = useState(true);
  const [loadingAI, setLoadingAI] = useState(false);
  const [interpretations, setInterpretations] = useState<CommunityInterpretations | null>(null);

  // Chart Data States
  const [orgTypeData, setOrgTypeData] = useState<any[]>([]);
  const [topOrgs, setTopOrgs] = useState<any[]>([]);
  const [roleData, setRoleData] = useState<any[]>([]);
  const [timelineData, setTimelineData] = useState<any[]>([]);

  // Cross Section Data
  const [crossSectionData, setCrossSectionData] = useState<any[]>([]); // For chart
  const [crossSectionStats, setCrossSectionStats] = useState<any>({}); // For AI

  // Data State for AI
  const [aiStats, setAiStats] = useState<any>(null);

  useEffect(() => {
    fetchData();
  }, []);

  // Effect to trigger AI only if enabled and data is ready
  useEffect(() => {
      if (autoAI && aiStats && !interpretations && !loadingAI) {
          runAI(aiStats);
      } else if (!autoAI) {
          setInterpretations(null);
      }
  }, [autoAI, aiStats]);

  const runAI = async (stats: any) => {
      setLoadingAI(true);
      try {
          const insights = await generateCommunityInsights(stats);
          setInterpretations(insights);
      } catch (e) {
          console.error("AI Error", e);
      } finally {
          setLoadingAI(false);
      }
  };

  const fetchData = async () => {
    setLoading(true);
    try {
        // 1. Fetch All Tables
        const [commRes, empRes] = await Promise.all([
            supabase.from('community_engagement').select('*'),
            supabase.from('employment_information').select('*')
        ]);

        const commData = commRes.data || [];
        const empData = empRes.data || [];

        // Map Employment by Survey ID for Cross-Ref
        const empMap = new Map();
        // Sort to ensure latest is used
        [...empData].sort((a,b) => a.id - b.id).forEach(e => empMap.set(e.survey_response_id, e));

        // --- PROCESSING ---

        // A. Org Types & Top Orgs
        const typeCounts: Record<string, number> = {};
        const nameCounts: Record<string, number> = {};
        const roleCounts: Record<string, number> = { Leader: 0, Officer: 0, Member: 0 };
        const yearCounts: Record<string, number> = {};

        // B. Cross Section Containers
        let leadersTotal = 0, leadersManagers = 0;
        let membersTotal = 0, membersManagers = 0;

        // Track user engagement to avoid double counting same user in cross-section
        const userHighestRole = new Map<string, 'Leader' | 'Officer' | 'Member'>();

        commData.forEach(record => {
            if (!record.organization_name) return;

            // 1. Org Type
            const type = categorizeOrg(record.organization_name);
            typeCounts[type] = (typeCounts[type] || 0) + 1;

            // 2. Specific Name (Cleaned)
            const cleanName = record.organization_name.trim();
            nameCounts[cleanName] = (nameCounts[cleanName] || 0) + 1;

            // 3. Role
            const roleCat = categorizeRole(record.role || '');
            roleCounts[roleCat]++;

            // 4. Timeline
            // Fix: Handle text dates like "2023 - Present" by extracting first 4 digits
            if (record.date_affiliated) {
                let year = 'Unknown';
                // Regex to find 4 digits (e.g., 2023)
                const match = record.date_affiliated.toString().match(/\d{4}/);
                if (match) {
                    year = match[0];
                } else {
                    // Fallback to date parsing
                    const d = new Date(record.date_affiliated);
                    if (!isNaN(d.getFullYear())) year = d.getFullYear().toString();
                }

                if (year !== 'Unknown') {
                    yearCounts[year] = (yearCounts[year] || 0) + 1;
                }
            }

            // 5. User Role Tracking for Cross-Section
            // We promote them to highest role found (Leader > Officer > Member)
            const currentHighest = userHighestRole.get(record.survey_response_id);
            if (!currentHighest) {
                userHighestRole.set(record.survey_response_id, roleCat);
            } else if (roleCat === 'Leader') {
                userHighestRole.set(record.survey_response_id, 'Leader');
            } else if (roleCat === 'Officer' && currentHighest === 'Member') {
                userHighestRole.set(record.survey_response_id, 'Officer');
            }
        });

        // C. Cross-Section Calculation
        userHighestRole.forEach((role, surveyId) => {
            const emp = empMap.get(surveyId);
            if (emp) {
                const isManagerial = ['Managerial', 'Department Head', 'Director', 'Vice President', 'Executive', 'Supervisory'].includes(emp.current_job_level);

                if (role === 'Leader' || role === 'Officer') {
                    leadersTotal++;
                    if (isManagerial) leadersManagers++;
                } else {
                    membersTotal++;
                    if (isManagerial) membersManagers++;
                }
            }
        });

        // --- FORMATTING ---

        // Org Types
        const orgTypesFormatted = Object.entries(typeCounts)
            .map(([name, value]) => ({ name, value }))
            .sort((a,b) => b.value - a.value);
        setOrgTypeData(orgTypesFormatted);

        // Top Orgs
        const topOrgsFormatted = Object.entries(nameCounts)
            .map(([name, value]) => ({ name, value }))
            .sort((a,b) => b.value - a.value)
            .slice(0, 5);
        setTopOrgs(topOrgsFormatted);

        // Roles
        const roleDataFormatted = Object.entries(roleCounts).map(([name, value]) => ({ name, value }));
        setRoleData(roleDataFormatted);

        // Timeline
        const timelineFormatted = Object.entries(yearCounts)
            .map(([year, count]) => ({ year, count }))
            .sort((a,b) => parseInt(a.year) - parseInt(b.year))
            .slice(-5); // Last 5 years
        setTimelineData(timelineFormatted);

        // Cross Section Chart Data
        const leaderRate = leadersTotal > 0 ? Math.round((leadersManagers / leadersTotal) * 100) : 0;
        const memberRate = membersTotal > 0 ? Math.round((membersManagers / membersTotal) * 100) : 0;

        setCrossSectionData([
            { group: 'Community Leaders', percentage: leaderRate, fill: '#f59e0b' }, // Gold
            { group: 'Regular Members', percentage: memberRate, fill: '#94a3b8' }    // Slate
        ]);
        setCrossSectionStats({ leaderManagerialRate: leaderRate, memberManagerialRate: memberRate });

        // --- PREPARE AI STATS ---
        const statsForAI = {
            orgTypeCounts: typeCounts,
            topOrgs: topOrgsFormatted.map(o => o.name),
            roleCounts: roleCounts,
            crossSection: { leaderManagerialRate: leaderRate, memberManagerialRate: memberRate },
            timelineData: timelineFormatted
        };
        setAiStats(statsForAI);

        // Mark fetch done
        setLoading(false);

    } catch (e) {
        console.error(e);
        setLoading(false);
    }
  };

  return (
    <div className="space-y-8 animate-fade-in pb-10">

        {/* ROW 1: Participation & Orgs */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

            {/* Org Types Pie */}
            <div className="bg-white/40 backdrop-blur-xl border border-white/50 shadow-lg shadow-indigo-500/5 p-6 rounded-3xl lg:col-span-1 flex flex-col">
                <div className="flex items-center gap-3 mb-6">
                    <div className="p-2 bg-indigo-100 text-indigo-600 rounded-xl"><Heart size={20}/></div>
                    <h4 className="font-bold text-slate-800">Participation by Type</h4>
                </div>
                <div className="h-64 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <PieChart>
                            <Pie
                                data={orgTypeData}
                                cx="50%"
                                cy="50%"
                                innerRadius={60}
                                outerRadius={80}
                                paddingAngle={5}
                                dataKey="value"
                            >
                                {orgTypeData.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                ))}
                            </Pie>
                            <Tooltip contentStyle={{borderRadius: '12px'}} />
                            <Legend verticalAlign="bottom" height={36} iconType="circle"/>
                        </PieChart>
                    </ResponsiveContainer>
                </div>
                <InsightCard text={interpretations?.participationAnalysis} loading={loadingAI} />
            </div>

            {/* Top Organizations Bar */}
            <div className="bg-white/40 backdrop-blur-xl border border-white/50 shadow-lg shadow-indigo-500/5 p-6 rounded-3xl lg:col-span-2 flex flex-col">
                <div className="flex items-center gap-3 mb-6">
                    <div className="p-2 bg-teal-100 text-teal-600 rounded-xl"><Landmark size={20}/></div>
                    <h4 className="font-bold text-slate-800">Top Organizations</h4>
                </div>
                <div className="h-64 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={topOrgs} layout="vertical" margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                            <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} opacity={0.3} />
                            <XAxis type="number" hide />
                            <YAxis dataKey="name" type="category" width={150} tick={{fontSize: 11, fontWeight: 'bold', fill: '#64748b'}} />
                            <Tooltip cursor={{fill: '#f0fdfa'}} contentStyle={{borderRadius: '12px'}} />
                            <Bar dataKey="value" fill="#2dd4bf" radius={[0, 4, 4, 0]} barSize={24} />
                        </BarChart>
                    </ResponsiveContainer>
                </div>
                <InsightCard text={interpretations?.orgTypeInsights} loading={loadingAI} />
            </div>
        </div>

        {/* ROW 2: The "Research Grade" Cross Section */}
        <div className="bg-gradient-to-r from-slate-800 to-slate-900 rounded-3xl p-8 text-white shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-500/20 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2"></div>

            <div className="relative z-10 grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">
                <div className="space-y-6">
                    <div className="inline-flex items-center gap-2 px-3 py-1 bg-white/10 rounded-full border border-white/20 text-xs font-bold text-indigo-200">
                        <Briefcase size={14} /> Employment Outcome Correlation
                    </div>
                    <div>
                        <h3 className="text-3xl font-black leading-tight mb-2">Does Civic Leadership Lead to Career Success?</h3>
                        <p className="text-slate-300 text-sm leading-relaxed">
                            Comparing the percentage of alumni in <strong>Managerial or Supervisory</strong> positions between those who held leadership roles in community organizations versus regular members.
                        </p>
                    </div>

                    <div className="bg-white/10 backdrop-blur-md p-5 rounded-2xl border border-white/10">
                        {loadingAI ? <div className="h-12 bg-white/10 rounded animate-pulse"></div> : (
                            <p className="text-sm italic font-medium text-white/90">
                                " {interpretations?.leadershipImpact || "Analysis pending or disabled."} "
                            </p>
                        )}
                    </div>
                </div>

                <div className="h-64 w-full bg-white/5 rounded-2xl p-4 border border-white/10">
                    <h5 className="text-xs font-bold text-center mb-4 text-slate-300 uppercase tracking-widest">Rate of Managerial Employment</h5>
                    <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={crossSectionData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} opacity={0.2} stroke="#fff" />
                            <XAxis dataKey="group" tick={{fill: '#e2e8f0', fontSize: 12, fontWeight: 'bold'}} axisLine={false} tickLine={false} />
                            <YAxis tick={{fill: '#e2e8f0', fontSize: 11}} axisLine={false} tickLine={false} unit="%" />
                            <Tooltip 
                                contentStyle={{borderRadius: '12px', border: 'none', backgroundColor: '#fff', color: '#333'}} 
                                cursor={{fill: 'rgba(255,255,255,0.1)'}}
                            />
                            <Bar dataKey="percentage" radius={[8, 8, 0, 0]} barSize={60}>
                                {crossSectionData.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={entry.fill} />
                                ))}
                            </Bar>
                        </BarChart>
                    </ResponsiveContainer>
                </div>
            </div>
        </div>

        {/* ROW 3: Role Distribution & Timeline */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            {/* Roles */}
            <div className="bg-white/40 backdrop-blur-xl border border-white/50 shadow-lg shadow-indigo-500/5 p-6 rounded-3xl flex flex-col">
                <div className="flex items-center gap-3 mb-6">
                    <div className="p-2 bg-amber-100 text-amber-600 rounded-xl"><Users size={20}/></div>
                    <h4 className="font-bold text-slate-800">Leadership Roles</h4>
                </div>
                <div className="h-64 w-full flex justify-center">
                    <ResponsiveContainer width="100%" height="100%">
                        <PieChart>
                            <Pie
                                data={roleData}
                                cx="50%"
                                cy="50%"
                                innerRadius={60}
                                outerRadius={80}
                                dataKey="value"
                                paddingAngle={5}
                            >
                                {roleData.map((entry, index) => (
                                    // @ts-ignore
                                    <Cell key={`cell-${index}`} fill={ROLE_COLORS[entry.name] || '#ccc'} />
                                ))}
                            </Pie>
                            <Tooltip contentStyle={{borderRadius: '12px'}} />
                            <Legend verticalAlign="bottom" />
                        </PieChart>
                    </ResponsiveContainer>
                </div>
            </div>

            {/* Timeline */}
            <div className="bg-white/40 backdrop-blur-xl border border-white/50 shadow-lg shadow-indigo-500/5 p-6 rounded-3xl flex flex-col">
                <div className="flex items-center gap-3 mb-6">
                    <div className="p-2 bg-green-100 text-green-600 rounded-xl"><TrendingUp size={20}/></div>
                    <h4 className="font-bold text-slate-800">Engagement Timeline</h4>
                </div>
                <div className="h-64 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={timelineData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                            <defs>
                                <linearGradient id="colorEngagement" x1="0" y1="0" x2="0" y2="1">
                                    <stop offset="5%" stopColor="#22c55e" stopOpacity={0.8}/>
                                    <stop offset="95%" stopColor="#22c55e" stopOpacity={0}/>
                                </linearGradient>
                            </defs>
                            <XAxis dataKey="year" tick={{fontSize: 11}} />
                            <YAxis tick={{fontSize: 11}} />
                            <Tooltip contentStyle={{borderRadius: '12px'}} />
                            <Area type="monotone" dataKey="count" stroke="#16a34a" strokeWidth={3} fillOpacity={1} fill="url(#colorEngagement)" />
                        </AreaChart>
                    </ResponsiveContainer>
                </div>
                <InsightCard text={interpretations?.timelineTrends} loading={loadingAI} />
            </div>
        </div>

    </div>
  );
};

export default CommunityAnalytics;

