import { GoogleGenAI, Schema, Type } from "@google/genai";
import { supabase } from '../lib/supabaseClient';
import { InternetAlumni } from '../types';

const SERPER_KEY = "b3403d9cd24afa5ba9e3a1d7df38792db7c4caad";
const API_KEY = "AIzaSyDUo8NlOC56gWYEETviAceCUd-mxoruplQ";
const ai = new GoogleGenAI({ apiKey: API_KEY });

const MODELS = ["gemini-2.0-flash"];

// Schema for Gemini to clean the scraped data
const cleanAlumniSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      full_name: { type: Type.STRING },
      course: { type: Type.STRING },
      graduation_year: { type: Type.INTEGER },
      current_job: { type: Type.STRING },
      industry: { type: Type.STRING },
      employment_status: { type: Type.STRING, enum: ['Employed', 'Unemployed', 'Self-Employed', 'Freelancer', 'Not Seeking Employment'] },
      job_relation: { type: Type.STRING, enum: ['Related', 'Non-Related'] }
    },
    required: ["full_name", "employment_status", "job_relation"]
  }
};

export const performAlumniSearch = async (): Promise<InternetAlumni[]> => {
  const myHeaders = new Headers();
  myHeaders.append("X-API-KEY", SERPER_KEY);
  myHeaders.append("Content-Type", "application/json");

  // Constant Query as requested
  const raw = JSON.stringify({
    "q": "site:linkedin.com/in (\"Laguna University\" \"Bachelor\" OR \"Laguna University\" \"BS\")",
    "num": 20 // Fetch up to 20 results per request
  });

  const requestOptions = {
    method: "POST",
    headers: myHeaders,
    body: raw,
    redirect: "follow" as RequestRedirect
  };

  try {
    const response = await fetch("https://google.serper.dev/search", requestOptions);
    const result = await response.json();

    if (!result.organic || result.organic.length === 0) {
        return [];
    }

    // Process with AI
    return await processRawSearchResults(result.organic);

  } catch (error) {
    console.error("Serper API Error:", error);
    throw new Error("Failed to fetch alumni data from the web.");
  }
};

const processRawSearchResults = async (results: any[]): Promise<InternetAlumni[]> => {
  const snippets = results.map((r: any) => `Title: ${r.title}, Snippet: ${r.snippet}, Link: ${r.link}`).join("\n---\n");

  const prompt = `
    You are a Data Scraper Cleaner. I will provide raw Google Search results for "Laguna University Alumni" on LinkedIn.

    Task:
    1. Extract specific alumni details.
    2. Infer 'course' and 'graduation_year' from the snippet if available. If unknown, put "Unknown" or null.
    3. Infer 'current_job' and 'industry'.
    4. Determine 'job_relation' (Related/Non-Related) based on the course and current job. If course is unknown, mark 'Non-Related'.
    5. Set 'employment_status' (mostly 'Employed' if they have a job title).

    Raw Data:
    ${snippets}

    Output strictly a JSON array based on the schema.
  `;

  for (const model of MODELS) {
    try {
      const response = await ai.models.generateContent({
        model: model,
        contents: { parts: [{ text: prompt }] },
        config: {
          responseMimeType: "application/json",
          responseSchema: cleanAlumniSchema,
        },
      });

      if (response.text) {
        const cleanedData = JSON.parse(response.text);

        // Post-processing: Add metadata and placeholder emails (required by DB schema)
        return cleanedData.map((alumni: any) => ({
            ...alumni,
            // Generate a placeholder unique email since scraping rarely gets real emails
            email: `${alumni.full_name.replace(/\s+/g, '.').toLowerCase()}.${Date.now().toString().slice(-4)}@mined.linkedin`,
            sourced_at: 'LinkedIn / Serper',
            created_at: new Date().toISOString()
        }));
      }
    } catch (error) {
      console.warn(`Model ${model} failed for cleaning alumni:`, error);
    }
  }

  return [];
};

