import { GoogleGenAI, Schema, Type } from "@google/genai";
import { supabase } from '../lib/supabaseClient';
import { InternetAlumni } from '../types';

const SERPER_KEY = "b3403d9cd24afa5ba9e3a1d7df38792db7c4caad";
const API_KEY = "AIzaSyDUo8NlOC56gWYEETviAceCUd-mxoruplQ";
const ai = new GoogleGenAI({ apiKey: API_KEY });

const MODELS = ["gemini-2.0-flash"];

// Schema for Gemini to clean the scraped data
// Note: 'Student' is added to enum to allow AI to classify them, but they will be filtered out before saving.
const cleanAlumniSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      full_name: { type: Type.STRING },
      course: { type: Type.STRING },
      graduation_year: { type: Type.INTEGER, description: "The year of graduation (End Date). Must be extracted. If not found, return null." },
      current_job: { type: Type.STRING, description: "Current Job Title. Leave empty if status is Unknown." },
      employment_status: { 
        type: Type.STRING, 
        enum: ['Employed', 'Unemployed', 'Self-Employed', 'Freelancer', 'Student', 'Not Seeking Employment', 'Unknown'],
        description: "Classify strictly. 'Freelancer' -> 'Self-Employed'. 'Open to work' -> 'Unemployed'. 'Student' -> 'Student'. If the title is generic (e.g. 'BS Accountancy Graduate', 'Alumni', 'Graduate') and NO other job is listed -> 'Unknown'." 
      },
      industry: { type: Type.STRING, description: "Infer the industry based on the current job title and company." },
      job_relation: { 
        type: Type.STRING, 
        enum: ['Related', 'Non-Related'],
        description: "Strictly analyze if the Current Job is related to the Course. If Unknown/Unemployed, leave blank or Non-Related."
      },
      link: { type: Type.STRING, description: "The direct URL link to the profile found in the input." }
    },
    required: ["full_name", "job_relation", "employment_status", "link"]
  }
};

export const performAlumniSearch = async (): Promise<InternetAlumni[]> => {
  const myHeaders = new Headers();
  myHeaders.append("X-API-KEY", SERPER_KEY);
  myHeaders.append("Content-Type", "application/json");

  // Hardcoded Query as requested
  const searchQuery = "site:linkedin.com/in (\"Laguna University\" \"Bachelor\" OR \"Laguna University\" \"BS\")";

  const raw = JSON.stringify({
    "q": searchQuery,
    "num": 20 // Fetch up to 20 results per request
  });

  const requestOptions = {
    method: "POST",
    headers: myHeaders,
    body: raw,
    redirect: "follow" as RequestRedirect
  };

  try {
    const response = await fetch("https://google.serper.dev/search", requestOptions);
    const result = await response.json();

    if (!result.organic || result.organic.length === 0) {
        return [];
    }

    // Process with AI
    return await processRawSearchResults(result.organic);

  } catch (error) {
    console.error("Search API Error:", error);
    throw new Error("Failed to fetch alumni data from the web.");
  }
};

const processRawSearchResults = async (results: any[]): Promise<InternetAlumni[]> => {
  // We include the link in the text block so the AI can extract it and map it to the person
  const snippets = results.map((r: any) => `Title: ${r.title}, Snippet: ${r.snippet}, Link: ${r.link}`).join("\n---\n");

  const prompt = `
    You are a Data Scraper Cleaner. I will provide raw Google Search results for "Laguna University Alumni" on LinkedIn.

    Task:
    1. Extract specific alumni details.
    2. **Link**: Extract the URL link provided in the text for each person.
    3. **Course & Grad Year**: Infer 'course' and 'graduation_year' (End Date).
    4. **Employment Status Logic**: 
       - "Freelancer", "Self-employed", "Business Owner", "Virtual Assistant" -> Set to 'Self-Employed'.
       - "Open to work", "Looking for opportunities", "Unemployed" -> Set to 'Unemployed'.
       - "Student", "Intern", "Undergraduate" (if this is their ONLY role) -> Set to 'Student'.
       - **GENERIC TITLES**: If the description or title only says "BS Accountancy Graduate", "Laguna University Alumni", "Graduate", "Alumni", "Cum Laude", etc., and DOES NOT list an actual company or job role -> Set to 'Unknown'. Do NOT classify as Unemployed.
       - Otherwise, if they have a specific job title -> Set to 'Employed'.
    5. **Job Relation**: STRICTLY compare the 'Course' vs 'Current Job'. 
       - If 'Unknown' or 'Unemployed', set to Non-Related.
    6. **Industry**: Infer based on job title.

    Raw Data:
    ${snippets}

    Output strictly a JSON array based on the schema.
  `;

  for (const model of MODELS) {
    try {
      const response = await ai.models.generateContent({
        model: model,
        contents: { parts: [{ text: prompt }] },
        config: {
          responseMimeType: "application/json",
          responseSchema: cleanAlumniSchema,
        },
      });

      if (response.text) {
        const cleanedData = JSON.parse(response.text);

        // Post-processing: Filter and Add metadata
        const validAlumni: InternetAlumni[] = [];

        for (const alumni of cleanedData) {
            // FILTER 1: EXCLUDE STUDENTS
            if (alumni.employment_status === 'Student') {
                continue;
            }
            if (alumni.current_job && alumni.current_job.toLowerCase().includes('student at laguna university')) {
                continue;
            }

            // FILTER 2: Must have Graduation Year (End Date)
            if (!alumni.graduation_year) {
                continue;
            }

            // FILTER 3: Data Quality Check - Handle Generic "Job Titles"
            // If the AI classified as 'Employed' but the job title looks generic (and wasn't caught by AI),
            // force it to 'Unknown'.
            const genericTitles = ['graduate', 'alumni', 'student', 'bs', 'bachelor', 'cum laude'];
            const jobLower = (alumni.current_job || '').toLowerCase();
            const isGeneric = genericTitles.some(t => jobLower.includes(t) && !jobLower.includes('engineer') && !jobLower.includes('developer') && !jobLower.includes('accountant')); // Simple heuristic to avoid false positives on real titles containing these words

            let finalStatus = alumni.employment_status;
            let finalJob = alumni.current_job;

            // Refine Status based on heuristic if strictly generic title found as the ONLY job info
            if (finalStatus === 'Employed' && (finalJob === '' || jobLower.includes('graduate of') || jobLower === 'alumni' || jobLower.includes('student'))) {
               finalStatus = 'Unknown';
               finalJob = '';
            }

            // Generate a unique placeholder email to satisfy DB UNIQUE NOT NULL constraint
            const uniqueSuffix = Date.now().toString(36) + Math.random().toString(36).substr(2);
            const sanitizedName = (alumni.full_name || 'unknown').replace(/[^a-zA-Z0-9]/g, '').toLowerCase();
            const email = `${sanitizedName}.${uniqueSuffix}@mined.placeholder`;

            // Normalize Freelancer
            if (finalStatus === 'Freelancer') finalStatus = 'Self-Employed';

            validAlumni.push({
                ...alumni,
                email: email,
                employment_status: finalStatus,
                current_job: finalJob,
                link: alumni.link, // Save the link
                sourced_at: 'LinkedIn / Web Mining',
                created_at: new Date().toISOString()
            });
        }

        return validAlumni;
      }
    } catch (error) {
      console.warn(`Model ${model} failed for cleaning alumni:`, error);
    }
  }

  return [];
};

export const saveMinedAlumni = async (alumniList: InternetAlumni[]) => {
    if (alumniList.length === 0) return;
    const { error } = await supabase.from('internet_alumni').insert(alumniList);
    if (error) throw error;
};

export const fetchMinedAnalytics = async () => {
    const { data, error } = await supabase.from('internet_alumni').select('*');
    if (error) throw error;

    const total = data.length;

    // Aggregations
    const industryCounts: Record<string, number> = {};
    const relationCounts: Record<string, number> = { Related: 0, "Non-Related": 0 };
    const statusCounts: Record<string, number> = { 'Employed': 0, 'Unemployed': 0, 'Self-Employed': 0, 'Unknown': 0 };

    data.forEach((alum: InternetAlumni) => {
        if (alum.industry) industryCounts[alum.industry] = (industryCounts[alum.industry] || 0) + 1;
        if (alum.job_relation) relationCounts[alum.job_relation] = (relationCounts[alum.job_relation] || 0) + 1;

        // Normalize status count
        let status = alum.employment_status;
        if (status === 'Freelancer') status = 'Self-Employed';
        if (!status) status = 'Unknown';

        // Ensure key exists
        statusCounts[status] = (statusCounts[status] || 0) + 1;
    });

    const topIndustries = Object.entries(industryCounts)
        .map(([name, value]) => ({ name, value }))
        .sort((a,b) => b.value - a.value)
        .slice(0, 5);

    const relationData = [
        { name: 'Related', value: relationCounts['Related'] },
        { name: 'Non-Related', value: relationCounts['Non-Related'] }
    ];

    const statusData = Object.entries(statusCounts).map(([name, value]) => ({ name, value }));

    return {
        total,
        topIndustries,
        relationData,
        statusData,
        recentRecords: data.sort((a,b) => new Date(b.created_at || 0).getTime() - new Date(a.created_at || 0).getTime()).slice(0, 10)
    };
};

