                  if (currentConfig.frequency === 'Quarterly') nextDate.setMonth(nextDate.getMonth() + 3);

                  const newConfig = { ...currentConfig, nextRun: nextDate.toISOString().split('T')[0] };
                  saveMiningConfig(newConfig);
                  setConfig(newConfig);
              }
          }
      } catch (error: any) {
