import { Globe, Download, Loader2, Database, Briefcase, CheckCircle, XCircle, RefreshCw, UserCheck, ExternalLink, Settings, Clock, Save, ToggleLeft, ToggleRight, Facebook, Linkedin, Lightbulb } from 'lucide-react';
